// ── Shruti handwritten SVG animation ─────────────────────────────
// Each letter is a single continuous SVG path drawn in cursive script.
// Paths are hand-crafted cubic bezier strokes that look like pen handwriting.
// viewBox per letter: 0 0 W 120  (baseline at y≈90, ascenders up to y≈10)

const SHRUTI_LETTERS = [
  {
    id: "S",
    w: 72,
    // S: starts top-right, sweeps left-up, curves right, sweeps left-down, curls right tail
    path: "M 58,22 C 44,10 18,12 16,30 C 14,46 52,50 52,66 C 52,84 24,90 12,80",
    strokeLen: 180,
  },
  {
    id: "H",
    w: 76,
    // H: left vertical down, up to crossbar, across, continue down right leg, tail
    path: "M 14,18 C 13,18 12,88 12,90 M 12,54 C 28,48 48,48 60,54 M 60,18 C 60,18 60,86 62,92",
    strokeLen: 240,
    multiStroke: true,
    paths: [
      { d: "M 14,18 C 13,30 12,70 12,90", len: 75 },
      { d: "M 12,54 C 25,46 46,46 60,54", len: 55, delay: 0.55 },
      { d: "M 60,18 C 60,32 60,70 62,92", len: 77, delay: 0.95 },
    ],
  },
  {
    id: "R",
    w: 68,
    multiStroke: true,
    paths: [
      { d: "M 14,20 C 13,40 13,70 14,92", len: 74 },                          // spine
      { d: "M 14,20 C 28,14 52,18 54,36 C 56,52 36,58 14,58", len: 120, delay: 0.55 }, // bowl
      { d: "M 14,58 C 30,56 44,68 58,92", len: 80, delay: 1.1 },              // leg
    ],
  },
  {
    id: "U",
    w: 68,
    multiStroke: true,
    paths: [
      { d: "M 14,20 C 13,55 13,74 16,82 C 22,96 48,96 54,82 C 58,72 58,50 58,20", len: 180 },
    ],
  },
  {
    id: "T",
    w: 62,
    multiStroke: true,
    paths: [
      { d: "M 31,14 C 31,40 31,70 33,92", len: 80 },          // vertical
      { d: "M 10,28 C 20,22 44,22 54,28", len: 55, delay: 0.6 }, // crossbar
    ],
  },
  {
    id: "I",
    w: 38,
    multiStroke: true,
    paths: [
      { d: "M 19,14 C 19,40 19,68 21,92", len: 80 },
      { d: "M 14,28 C 16,24 24,22 26,26", len: 22, delay: 0 },     // top serif
      { d: "M 16,90 C 18,92 26,94 28,90", len: 22, delay: 0.6 },   // bottom serif
    ],
  },
];

// Letter base delays (cumulative, seconds)
const LETTER_DELAYS = [0, 1.0, 2.1, 3.4, 4.5, 5.4];
const WRITE_DURATION = 0.9; // seconds per stroke

function ShrutiHandwritten({ startWrite, delayOffset = 0, compact = false }) {
  const totalW = SHRUTI_LETTERS.reduce((a, l) => a + l.w, 0) + 8 * (SHRUTI_LETTERS.length - 1);
  const H = 120;

  return (
    <svg
      viewBox={`0 0 ${totalW} ${H}`}
      style={{
        width: compact ? "min(78vw, 340px)" : "min(92vw, 680px)",
        height: "auto",
        overflow: "visible",
        filter: "drop-shadow(0 0 24px rgba(255,217,61,0.55)) drop-shadow(0 0 8px rgba(255,107,157,0.4))",
      }}
    >
      <defs>
        <linearGradient id="shrutiGrad" x1="0%" y1="0%" x2="100%" y2="0%">
          <stop offset="0%"   stopColor="#FFD93D" />
          <stop offset="40%"  stopColor="#fff" />
          <stop offset="70%"  stopColor="#FF6B9D" />
          <stop offset="100%" stopColor="#CC5DE8" />
        </linearGradient>
      </defs>

      {(() => {
        let xOffset = 0;
        return SHRUTI_LETTERS.map((letter, li) => {
          const x = xOffset;
          xOffset += letter.w + 8;
          const baseDelay = LETTER_DELAYS[li];

          const strokes = letter.paths || [{ d: letter.path, len: letter.strokeLen, delay: 0 }];

          return (
            <g key={letter.id} transform={`translate(${x}, 0)`}>
              {strokes.map((stroke, si) => {
                const strokeDelay = delayOffset + baseDelay + (stroke.delay || 0);
                const animStyle = startWrite
                  ? {
                      strokeDasharray: stroke.len,
                      strokeDashoffset: stroke.len,
                      animation: `drawStroke ${WRITE_DURATION}s cubic-bezier(0.4,0,0.2,1) ${strokeDelay}s forwards`,
                    }
                  : {
                      strokeDasharray: stroke.len,
                      strokeDashoffset: stroke.len,
                    };

                return (
                  <path
                    key={si}
                    d={stroke.d}
                    fill="none"
                    stroke="url(#shrutiGrad)"
                    strokeWidth={7}
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    style={animStyle}
                  />
                );
              })}

              {/* Ink dot at start of each letter — appears with letter */}
              {startWrite && (
                <circle
                  cx={strokes[0].d.match(/M\s*([\d.]+)/)?.[1] ?? 20}
                  cy={strokes[0].d.match(/M\s*[\d.]+,([\d.]+)/)?.[1] ?? 20}
                  r={4}
                  fill="#FFD93D"
                  opacity={0}
                  style={{
                    animation: `inkDot 0.3s ease ${baseDelay}s forwards`,
                  }}
                />
              )}
            </g>
          );
        });
      })()}
    </svg>
  );
}

// ── Timer ring ────────────────────────────────────────────────────
function TimerRing({ progress, seconds }) {
  const r = 22;
  const circ = 2 * Math.PI * r;
  const dash = circ * (1 - progress);
  return (
    <div style={{ position: "relative", width: 60, height: 60, flexShrink: 0 }}>
      <svg width={60} height={60} style={{ transform: "rotate(-90deg)" }}>
        <circle cx={30} cy={30} r={r} fill="none" stroke="rgba(255,255,255,0.15)" strokeWidth={4} />
        <circle
          cx={30} cy={30} r={r} fill="none"
          stroke="#FFD93D" strokeWidth={4}
          strokeDasharray={circ}
          strokeDashoffset={dash}
          strokeLinecap="round"
          style={{ transition: "stroke-dashoffset 1s linear" }}
        />
      </svg>
      <span style={{
        position: "absolute", inset: 0, display: "flex", alignItems: "center", justifyContent: "center",
        fontFamily: "'Space Mono', monospace", fontSize: 15, fontWeight: 700, color: "#FFD93D"
      }}>{seconds}</span>
    </div>
  );
}

